import{_ as t,o as i,c as a,a2 as o}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"2023年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2023年/核心总结.md","filePath":"01_letters/2023年/核心总结.md"}'),e={name:"01_letters/2023年/核心总结.md"};function r(u,l,n,q,s,h){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="_2023年巴菲特致股东信核心总结" tabindex="-1">2023年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2023年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2023年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="查理·芒格-伯克希尔的缔造者" tabindex="-1">查理·芒格：伯克希尔的缔造者 <a class="header-anchor" href="#查理·芒格-伯克希尔的缔造者" aria-label="Permalink to &quot;查理·芒格：伯克希尔的缔造者&quot;">​</a></h2><ul><li>查理·芒格于2023年11月28日去世，享年99岁，距100岁生日仅差33天</li><li>巴菲特称芒格为伯克希尔的&quot;缔造者&quot;，自己只是&quot;总承包商&quot;</li><li>芒格的核心贡献：1965年说服巴菲特放弃格雷厄姆式&quot;捡便宜&quot;策略，转而以合理价格收购优秀企业</li><li>芒格从不居功，甘当幕后推手，从未在巴菲特犯错时&quot;提醒他&quot;</li><li>两人的关系既是兄弟，又如父子</li></ul><h2 id="经营业绩" tabindex="-1">经营业绩 <a class="header-anchor" href="#经营业绩" aria-label="Permalink to &quot;经营业绩&quot;">​</a></h2><ul><li><strong>经营收益</strong>：2023年374亿美元（2022年309亿美元，2021年276亿美元）</li><li><strong>GAAP净收益</strong>：2023年960亿美元，但该数字因包含未实现资本利得而失真</li><li>巴菲特强调&quot;经营收益&quot;远比GAAP&quot;净收益&quot;更有参考价值</li><li>伯克希尔年底GAAP净资产达5610亿美元，占标普500全部公司净资产的近6%</li></ul><h2 id="投资理念" tabindex="-1">投资理念 <a class="header-anchor" href="#投资理念" aria-label="Permalink to &quot;投资理念&quot;">​</a></h2><ul><li>目标：拥有基本且持久良好经济效益的企业（全部或部分持有）</li><li>偏好能以高回报率持续部署额外资本的罕见企业</li><li>坦言&quot;规模是障碍&quot;，五年内将庞大基数翻番不可能</li><li>期望伯克希尔比普通美国公司做得&quot;略好&quot;，以更低永久性资本损失风险运营</li><li>引用格雷厄姆名言：&quot;短期市场是投票机，长期市场是称重机&quot;</li></ul><h2 id="秘密武器-极端财务保守主义" tabindex="-1">&quot;秘密武器&quot;：极端财务保守主义 <a class="header-anchor" href="#秘密武器-极端财务保守主义" aria-label="Permalink to &quot;&quot;秘密武器&quot;：极端财务保守主义&quot;">​</a></h2><ul><li>永远不冒永久性资本损失的风险</li><li>持有远超常规水平的现金和美国国债</li><li>2008年恐慌中无需依赖任何商业票据、银行信贷或债务市场</li><li>不支付股息，股票回购完全自由裁量</li><li>目标：在经济灾难中为国家&quot;灭火&quot;，而非&quot;放火&quot;</li></ul><h2 id="重点持仓" tabindex="-1">重点持仓 <a class="header-anchor" href="#重点持仓" aria-label="Permalink to &quot;重点持仓&quot;">​</a></h2><ul><li><strong>可口可乐与美国运通</strong>：2023年零买卖，延续20多年&quot;长睡&quot;策略；美国运通年收益份额已远超当初13亿美元的成本</li><li><strong>西方石油</strong>：持股27.8%，欣赏其美国油气资产和碳捕集领先地位；无意收购或管理</li><li><strong>日本五大商社</strong>（伊藤忠、丸红、三菱、三井、住友）：各持股约9%，总成本1.6万亿日元，市值2.9万亿日元，美元计价未实现收益80亿美元；用1.3万亿日元债券融资对冲汇率风险</li><li><strong>苹果</strong>：大额持仓（信中提及但未详细展开）</li></ul><h2 id="业务表现" tabindex="-1">业务表现 <a class="header-anchor" href="#业务表现" aria-label="Permalink to &quot;业务表现&quot;">​</a></h2><ul><li>保险承保利润：54亿美元（2022年亏损3000万美元）</li><li>保险投资收益：96亿美元（大幅增长）</li><li>BNSF铁路和BHE能源未达预期，巴菲特承认预测失误</li><li>BNSF资本需求巨大，复制其资产至少需5000亿美元</li></ul><h2 id="关键金句" tabindex="-1">关键金句 <a class="header-anchor" href="#关键金句" aria-label="Permalink to &quot;关键金句&quot;">​</a></h2><ul><li>&quot;发现一家真正出色的企业时，坚持持有它。耐心是有回报的。&quot;</li><li>&quot;华尔街希望客户赚钱，但真正让从业者兴奋的是疯狂的交易活动。&quot;</li><li>&quot;永远不要指望在与骗子打交道时能阻止他欺骗你。&quot;</li><li>&quot;美国一直是投资者的乐土。他们需要做的只是安静地坐着，不听任何人的话。&quot;</li></ul>',15)])])}const c=t(e,[["render",r]]);export{_ as __pageData,c as default};
